static void Merge(const std::string &Input,
                  const std::vector<std::string> Result,
                  size_t NumNewFeatures) {
  Merger M;
  std::vector<std::string> NewFiles;
  EXPECT_TRUE(M.Parse(Input, true));
  EXPECT_EQ(NumNewFeatures, M.Merge(&NewFiles));
  EQ(NewFiles, Result);
}

